const config = {
  "previewFeatures": [],
  "clientVersion": "7.8.0",
  "engineVersion": "3c6e192761c0362d496ed980de936e2f3cebcd3a",
  "activeProvider": "postgresql",
  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// --------------------------------------------------\n// 1. Tenancy Core\n// --------------------------------------------------\n\nmodel Organization {\n  id        String   @id @default(uuid()) @db.Uuid\n  name      String\n  slug      String   @unique\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  companies   Company[]\n  territories Territory[]\n  teams       Team[]\n  roles       Role[]\n  users       User[]\n  sessions    Session[]\n  auditLogs   AuditLog[]\n  leads       Lead[]\n\n  prospects       Prospect[]\n  importJobs      ImportJob[]\n  emailCampaigns  EmailCampaign[]\n  emailActivities EmailActivity[]\n  aiAnalyses      AiAnalysis[]\n  emailTemplates  EmailTemplate[]\n\n  attendances           Attendance[]\n  visits                Visit[]\n  expenses              Expense[]\n  dailyActivities       DailyActivityReport[]\n  targets               Target[]\n  notifications         Notification[]\n  notificationTemplates NotificationTemplate[]\n  tasks                 Task[]\n  beatPlans             BeatPlan[]\n  calendarEvents        CalendarEvent[]\n  workflowSettings      WorkflowSettings[]\n  notificationPrefs     NotificationPreference[]\n  businessRules         BusinessRuleConfig[]\n  campaigns             Campaign[]\n}\n\n// --------------------------------------------------\n// 2. Corporate Hierarchy\n// --------------------------------------------------\n\nmodel Company {\n  id             String  @id @default(uuid()) @db.Uuid\n  organizationId String  @db.Uuid\n  name           String\n  code           String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  branches     Branch[]\n  territories  Territory[]\n\n  @@unique([organizationId, code])\n}\n\nmodel Branch {\n  id        String  @id @default(uuid()) @db.Uuid\n  companyId String  @db.Uuid\n  name      String\n  code      String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  company     Company      @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  departments Department[]\n  teams       Team[]\n  users       User[]\n\n  @@unique([companyId, code])\n}\n\nmodel Department {\n  id       String  @id @default(uuid()) @db.Uuid\n  branchId String  @db.Uuid\n  name     String\n  code     String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  branch Branch @relation(fields: [branchId], references: [id], onDelete: Cascade)\n  teams  Team[]\n  users  User[]\n\n  @@unique([branchId, code])\n}\n\nmodel Territory {\n  id             String  @id @default(uuid()) @db.Uuid\n  organizationId String  @db.Uuid\n  companyId      String? @db.Uuid\n  name           String\n  description    String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  company      Company?     @relation(fields: [companyId], references: [id], onDelete: SetNull)\n  teams        Team[]\n  users        User[]\n  leads        Lead[]\n}\n\nmodel Team {\n  id             String  @id @default(uuid()) @db.Uuid\n  organizationId String  @db.Uuid\n  branchId       String  @db.Uuid\n  departmentId   String? @db.Uuid\n  territoryId    String? @db.Uuid\n  name           String\n  description    String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  branch       Branch       @relation(fields: [branchId], references: [id], onDelete: Cascade)\n  department   Department?  @relation(fields: [departmentId], references: [id], onDelete: SetNull)\n  territory    Territory?   @relation(fields: [territoryId], references: [id], onDelete: SetNull)\n  users        User[]\n  targets      Target[]\n}\n\n// --------------------------------------------------\n// 3. Authentication & RBAC\n// --------------------------------------------------\n\nmodel Role {\n  id             String  @id @default(uuid()) @db.Uuid\n  organizationId String? @db.Uuid\n  name           String\n  description    String?\n  isSystem       Boolean @default(false)\n  level          Int?\n  parentRoleId   String? @db.Uuid\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization?    @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  parentRole   Role?            @relation(\"RoleHierarchy\", fields: [parentRoleId], references: [id], onDelete: SetNull)\n  childRoles   Role[]           @relation(\"RoleHierarchy\")\n  permissions  RolePermission[]\n  users        UserRole[]\n\n  @@unique([organizationId, name])\n}\n\nmodel Permission {\n  id          String  @id @default(uuid()) @db.Uuid\n  name        String  @unique\n  slug        String  @unique\n  description String?\n  moduleName  String\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  roles RolePermission[]\n}\n\nmodel RolePermission {\n  roleId       String   @db.Uuid\n  permissionId String   @db.Uuid\n  assignedAt   DateTime @default(now())\n\n  role       Role       @relation(fields: [roleId], references: [id], onDelete: Cascade)\n  permission Permission @relation(fields: [permissionId], references: [id], onDelete: Cascade)\n\n  @@id([roleId, permissionId])\n}\n\n// --------------------------------------------------\n// 4. Users\n// --------------------------------------------------\n\nmodel User {\n  id             String  @id @default(uuid()) @db.Uuid\n  organizationId String  @db.Uuid\n  branchId       String? @db.Uuid\n  departmentId   String? @db.Uuid\n  teamId         String? @db.Uuid\n  territoryId    String? @db.Uuid\n  managerId      String? @db.Uuid\n\n  email                      String\n  passwordHash               String\n  firstName                  String\n  lastName                   String\n  phoneNumber                String?\n  isActive                   Boolean   @default(true)\n  emailVerifiedAt            DateTime?\n  emailVerificationOtp       String?\n  emailVerificationExpiresAt DateTime?\n  failedLoginAttempts        Int       @default(0)\n  lockoutExpiresAt           DateTime?\n  passwordResetOtp           String?\n  passwordResetExpiresAt     DateTime?\n  deletedAt                  DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  branch       Branch?      @relation(fields: [branchId], references: [id], onDelete: SetNull)\n  department   Department?  @relation(fields: [departmentId], references: [id], onDelete: SetNull)\n  team         Team?        @relation(fields: [teamId], references: [id], onDelete: SetNull)\n  territory    Territory?   @relation(fields: [territoryId], references: [id], onDelete: SetNull)\n  manager      User?        @relation(\"UserReporting\", fields: [managerId], references: [id], onDelete: SetNull)\n  subordinates User[]       @relation(\"UserReporting\")\n\n  roles              UserRole[]\n  sessions           Session[]\n  refreshTokens      RefreshToken[]\n  auditLogs          AuditLog[]\n  passwordHistories  PasswordHistory[]\n  assignedLeads      Lead[]                  @relation(\"LeadAssignee\")\n  createdLeads       Lead[]                  @relation(\"LeadCreator\")\n  leadActivities     LeadActivity[]\n  leadNotes          LeadNote[]\n  leadDocuments      LeadDocument[]\n  followUps          LeadFollowUp[]          @relation(\"FollowUpOwner\")\n  meetingsOrganized  LeadMeeting[]           @relation(\"MeetingOrganizer\")\n  assignmentHistory  LeadAssignmentHistory[]\n  leadConversions    LeadConversion[]\n  uploadedImportJobs ImportJob[]\n  createdCampaigns   EmailCampaign[]\n  createdTemplates   EmailTemplate[]         @relation(\"TemplateCreatedBy\")\n\n  attendances       Attendance[]\n  visits            Visit[]\n  expenses          Expense[]\n  dailyActivities   DailyActivityReport[]\n  targets           Target[]\n  notifications     Notification[]\n  expensesApproved  Expense[]                @relation(\"ExpenseApprover\")\n  tasks             Task[]\n  beatPlans         BeatPlan[]\n  calendarEvents    CalendarEvent[]\n  notificationPrefs NotificationPreference[]\n  campaignsCreated  Campaign[]               @relation(\"CampaignCreatedBy\")\n  campaignsUpdated  Campaign[]               @relation(\"CampaignUpdatedBy\")\n\n  @@unique([organizationId, email])\n}\n\nmodel UserRole {\n  userId     String   @db.Uuid\n  roleId     String   @db.Uuid\n  assignedAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n  role Role @relation(fields: [roleId], references: [id], onDelete: Cascade)\n\n  @@id([userId, roleId])\n}\n\n// --------------------------------------------------\n// 5. Sessions\n// --------------------------------------------------\n\nmodel Session {\n  id             String   @id @default(uuid()) @db.Uuid\n  organizationId String   @db.Uuid\n  userId         String   @db.Uuid\n  token          String   @unique\n  userAgent      String?\n  ipAddress      String?\n  expiresAt      DateTime\n\n  createdAt DateTime @default(now())\n\n  organization  Organization   @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  user          User           @relation(fields: [userId], references: [id], onDelete: Cascade)\n  refreshTokens RefreshToken[]\n}\n\nmodel RefreshToken {\n  id        String   @id @default(uuid()) @db.Uuid\n  userId    String   @db.Uuid\n  sessionId String   @db.Uuid\n  token     String   @unique\n  isRevoked Boolean  @default(false)\n  expiresAt DateTime\n\n  createdAt DateTime @default(now())\n\n  user    User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  session Session @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n}\n\n// --------------------------------------------------\n// 6. Audit & Password History\n// --------------------------------------------------\n\nmodel AuditLog {\n  id             String  @id @default(uuid()) @db.Uuid\n  organizationId String  @db.Uuid\n  userId         String? @db.Uuid\n  action         String\n  moduleName     String\n  details        Json?\n  ipAddress      String?\n  userAgent      String?\n\n  createdAt DateTime @default(now())\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  user         User?        @relation(fields: [userId], references: [id], onDelete: SetNull)\n}\n\nmodel PasswordHistory {\n  id           String @id @default(uuid()) @db.Uuid\n  userId       String @db.Uuid\n  passwordHash String\n\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\n// ==================================================\n// PHASE 3 & 4 — Lead Management\n// ==================================================\n\n// --------------------------------------------------\n// 7. Lead — Core record\n// --------------------------------------------------\n\nmodel Lead {\n  id             String  @id @default(uuid()) @db.Uuid\n  organizationId String  @db.Uuid\n  assignedToId   String? @db.Uuid\n  createdById    String  @db.Uuid\n  territoryId    String? @db.Uuid\n  branchId       String? @db.Uuid\n  teamId         String? @db.Uuid\n\n  // Contact identity\n  firstName String\n  lastName  String\n  email     String?\n  phone     String?\n  company   String?\n  jobTitle  String?\n  website   String?\n\n  // Classification\n  industry    String?\n  companySize String?\n  source      LeadSource @default(MANUAL)\n\n  // Address\n  addressLine1 String?\n  city         String?\n  state        String?\n  country      String?\n  postalCode   String?\n\n  // Lead state\n  status        LeadStatus        @default(NEW)\n  priority      LeadPriority      @default(MEDIUM)\n  qualification LeadQualification @default(UNQUALIFIED)\n  score         Float             @default(0)\n  notes         String?\n  tags          String[]          @default([])\n\n  // Conversion tracking\n  isConverted Boolean   @default(false)\n  convertedAt DateTime?\n\n  // Soft delete\n  deletedAt DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization      Organization            @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  assignedTo        User?                   @relation(\"LeadAssignee\", fields: [assignedToId], references: [id], onDelete: SetNull)\n  createdBy         User                    @relation(\"LeadCreator\", fields: [createdById], references: [id])\n  territory         Territory?              @relation(fields: [territoryId], references: [id], onDelete: SetNull)\n  activities        LeadActivity[]\n  notes_list        LeadNote[]\n  documents         LeadDocument[]\n  followUps         LeadFollowUp[]\n  meetings          LeadMeeting[]\n  assignmentHistory LeadAssignmentHistory[]\n  conversions       LeadConversion[]\n  visits            Visit[]\n  campaignLeads     CampaignLead[]\n\n  @@index([organizationId, status])\n  @@index([organizationId, assignedToId])\n  @@index([organizationId, qualification])\n  @@index([organizationId, score])\n  @@index([organizationId, deletedAt])\n  @@index([organizationId, source])\n  @@index([organizationId, isConverted])\n}\n\n// --------------------------------------------------\n// 8. Lead Activity Timeline\n// --------------------------------------------------\n\nmodel LeadActivity {\n  id             String       @id @default(uuid()) @db.Uuid\n  organizationId String       @db.Uuid\n  leadId         String       @db.Uuid\n  performedById  String?      @db.Uuid\n  activityType   ActivityType\n  title          String\n  description    String?\n  metadata       Json?\n\n  createdAt DateTime @default(now())\n\n  lead        Lead  @relation(fields: [leadId], references: [id], onDelete: Cascade)\n  performedBy User? @relation(fields: [performedById], references: [id], onDelete: SetNull)\n\n  @@index([leadId])\n  @@index([organizationId, leadId])\n  @@index([organizationId, activityType])\n}\n\n// --------------------------------------------------\n// 9. Lead Notes\n// Dedicated notes with pin support, edit/delete, internal flag\n// --------------------------------------------------\n\nmodel LeadNote {\n  id             String    @id @default(uuid()) @db.Uuid\n  organizationId String    @db.Uuid\n  leadId         String    @db.Uuid\n  authorId       String    @db.Uuid\n  content        String\n  isPinned       Boolean   @default(false)\n  isInternal     Boolean   @default(false) // Internal notes hidden from external views\n  editedAt       DateTime?\n  deletedAt      DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  lead   Lead @relation(fields: [leadId], references: [id], onDelete: Cascade)\n  author User @relation(fields: [authorId], references: [id])\n\n  @@index([leadId, deletedAt])\n  @@index([leadId, isPinned])\n}\n\n// --------------------------------------------------\n// 10. Lead Documents\n// File upload with versioning and category support\n// --------------------------------------------------\n\nmodel LeadDocument {\n  id             String           @id @default(uuid()) @db.Uuid\n  organizationId String           @db.Uuid\n  leadId         String           @db.Uuid\n  uploadedById   String           @db.Uuid\n  parentId       String?          @db.Uuid // Non-null = this is a new version of parentId\n  category       DocumentCategory @default(GENERAL)\n  name           String // Display name\n  originalName   String // Original file name on upload\n  mimeType       String\n  sizeBytes      Int\n  filePath       String // Server-side storage path\n  version        Int              @default(1)\n  description    String?\n  deletedAt      DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  lead       Lead           @relation(fields: [leadId], references: [id], onDelete: Cascade)\n  uploadedBy User           @relation(fields: [uploadedById], references: [id])\n  parent     LeadDocument?  @relation(\"DocumentVersions\", fields: [parentId], references: [id])\n  versions   LeadDocument[] @relation(\"DocumentVersions\")\n\n  @@index([leadId, deletedAt])\n  @@index([leadId, category])\n}\n\n// --------------------------------------------------\n// 11. Lead Follow-Up\n// --------------------------------------------------\n\nmodel LeadFollowUp {\n  id             String         @id @default(uuid()) @db.Uuid\n  organizationId String         @db.Uuid\n  leadId         String         @db.Uuid\n  ownerId        String         @db.Uuid // Responsible user\n  title          String\n  description    String?\n  dueAt          DateTime\n  completedAt    DateTime?\n  cancelledAt    DateTime?\n  status         FollowUpStatus @default(SCHEDULED)\n  reminderSentAt DateTime?\n  deletedAt      DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  lead  Lead @relation(fields: [leadId], references: [id], onDelete: Cascade)\n  owner User @relation(\"FollowUpOwner\", fields: [ownerId], references: [id])\n\n  @@index([leadId])\n  @@index([organizationId, status])\n  @@index([organizationId, ownerId, dueAt])\n}\n\n// --------------------------------------------------\n// 12. Lead Meeting\n// --------------------------------------------------\n\nmodel LeadMeeting {\n  id              String        @id @default(uuid()) @db.Uuid\n  organizationId  String        @db.Uuid\n  leadId          String        @db.Uuid\n  organizerId     String        @db.Uuid\n  title           String\n  agenda          String?\n  location        String?\n  meetingUrl      String?\n  scheduledAt     DateTime\n  durationMinutes Int           @default(60)\n  status          MeetingStatus @default(SCHEDULED)\n  outcome         String?\n  meetingNotes    String?\n  cancelledAt     DateTime?\n  cancelReason    String?\n  participants    Json          @default(\"[]\") // Array of { userId, name, email, role }\n  deletedAt       DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  lead      Lead @relation(fields: [leadId], references: [id], onDelete: Cascade)\n  organizer User @relation(\"MeetingOrganizer\", fields: [organizerId], references: [id])\n\n  @@index([leadId])\n  @@index([organizationId, status])\n  @@index([organizationId, organizerId])\n}\n\n// --------------------------------------------------\n// 13. Lead Assignment History\n// --------------------------------------------------\n\nmodel LeadAssignmentHistory {\n  id             String         @id @default(uuid()) @db.Uuid\n  organizationId String         @db.Uuid\n  leadId         String         @db.Uuid\n  assignedToId   String?        @db.Uuid // Null = unassigned\n  assignedById   String         @db.Uuid\n  assignmentType AssignmentType\n  reason         String?\n  assignedAt     DateTime       @default(now())\n\n  lead       Lead  @relation(fields: [leadId], references: [id], onDelete: Cascade)\n  assignedTo User? @relation(fields: [assignedToId], references: [id], onDelete: SetNull)\n\n  @@index([leadId])\n  @@index([organizationId, assignedToId])\n}\n\n// --------------------------------------------------\n// 14. Lead Conversion\n// Track conversion to Customer, Contact, or Opportunity\n// --------------------------------------------------\n\nmodel LeadConversion {\n  id               String         @id @default(uuid()) @db.Uuid\n  organizationId   String         @db.Uuid\n  leadId           String         @db.Uuid\n  convertedById    String         @db.Uuid\n  conversionType   ConversionType // CUSTOMER | CONTACT | OPPORTUNITY\n  targetEntityId   String?        @db.Uuid // ID in target module (once implemented)\n  targetEntityType String? // \"Customer\" | \"Contact\" | \"Opportunity\"\n  notes            String?\n  convertedAt      DateTime       @default(now())\n\n  lead        Lead @relation(fields: [leadId], references: [id], onDelete: Cascade)\n  convertedBy User @relation(fields: [convertedById], references: [id])\n\n  @@index([leadId])\n  @@index([organizationId, conversionType])\n}\n\n// --------------------------------------------------\n// 15. Lead Export Job\n// --------------------------------------------------\n\nmodel LeadExportJob {\n  id             String       @id @default(uuid()) @db.Uuid\n  organizationId String       @db.Uuid\n  requestedById  String       @db.Uuid\n  format         ExportFormat\n  filters        Json\n  totalRecords   Int          @default(0)\n  status         ExportStatus @default(PENDING)\n  filePath       String?\n  errorMessage   String?\n  expiresAt      DateTime?\n  completedAt    DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([organizationId, requestedById])\n  @@index([organizationId, status])\n}\n\n// --------------------------------------------------\n// 16. Enums\n// --------------------------------------------------\n\nenum LeadSource {\n  MANUAL\n  API\n  REFERRAL\n  WEBSITE\n  SOCIAL_MEDIA\n  EVENT\n  CAMPAIGN\n  OTHER\n}\n\nenum LeadStatus {\n  NEW\n  CONTACTED\n  QUALIFIED\n  PROPOSAL\n  NEGOTIATION\n  WON\n  LOST\n  ARCHIVED\n}\n\nenum LeadPriority {\n  LOW\n  MEDIUM\n  HIGH\n  URGENT\n}\n\nenum LeadQualification {\n  UNQUALIFIED\n  COLD\n  WARM\n  HOT\n}\n\nenum ActivityType {\n  CREATED\n  UPDATED\n  STATUS_CHANGED\n  PRIORITY_CHANGED\n  ASSIGNED\n  NOTE_ADDED\n  NOTE_EDITED\n  NOTE_DELETED\n  NOTE_PINNED\n  DOCUMENT_UPLOADED\n  DOCUMENT_DELETED\n  FOLLOW_UP_SCHEDULED\n  FOLLOW_UP_COMPLETED\n  FOLLOW_UP_CANCELLED\n  MEETING_SCHEDULED\n  MEETING_UPDATED\n  MEETING_COMPLETED\n  MEETING_CANCELLED\n  SCORE_UPDATED\n  QUALIFICATION_CHANGED\n  CONVERTED\n  EXPORTED\n  DELETED\n  RESTORED\n}\n\nenum DocumentCategory {\n  GENERAL\n  CONTRACT\n  PROPOSAL\n  PRESENTATION\n  INVOICE\n  IDENTITY\n  OTHER\n}\n\nenum FollowUpStatus {\n  SCHEDULED\n  COMPLETED\n  CANCELLED\n  OVERDUE\n}\n\nenum MeetingStatus {\n  SCHEDULED\n  IN_PROGRESS\n  COMPLETED\n  CANCELLED\n  NO_SHOW\n}\n\nenum AssignmentType {\n  MANUAL\n  AUTO\n  ROUND_ROBIN\n  TERRITORY_BASED\n  TEAM_BASED\n  REASSIGNED\n  UNASSIGNED\n}\n\nenum ConversionType {\n  CUSTOMER\n  CONTACT\n  OPPORTUNITY\n}\n\nenum ExportFormat {\n  CSV\n  EXCEL\n}\n\nenum ExportStatus {\n  PENDING\n  PROCESSING\n  COMPLETED\n  FAILED\n}\n\n// ==================================================\n// PHASE 5 — AI Lead Engine\n// ==================================================\n\n// --------------------------------------------------\n// 17. Prospect\n// Top of funnel raw contact\n// --------------------------------------------------\n\nmodel Prospect {\n  id             String  @id @default(uuid()) @db.Uuid\n  organizationId String  @db.Uuid\n  importJobId    String? @db.Uuid\n\n  email     String\n  firstName String?\n  lastName  String?\n  company   String?\n  jobTitle  String?\n  phone     String?\n  website   String?\n\n  // Cleaned / Enrichment data\n  industry    String?\n  companySize String?\n  country     String?\n  state       String?\n  city        String?\n\n  score               Float                 @default(0)\n  qualificationStatus ProspectQualification @default(UNQUALIFIED)\n\n  isConvertedToLead Boolean @default(false)\n  leadId            String? @db.Uuid\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization      Organization       @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  importJob         ImportJob?         @relation(fields: [importJobId], references: [id], onDelete: SetNull)\n  emailActivities   EmailActivity[]\n  campaignProspects CampaignProspect[]\n  aiAnalyses        AiAnalysis[]\n\n  @@unique([organizationId, email])\n  @@index([organizationId, qualificationStatus])\n  @@index([organizationId, isConvertedToLead])\n}\n\n// --------------------------------------------------\n// 18. Import Job\n// --------------------------------------------------\n\nmodel ImportJob {\n  id               String       @id @default(uuid()) @db.Uuid\n  organizationId   String       @db.Uuid\n  uploadedById     String       @db.Uuid\n  fileName         String\n  originalName     String\n  status           ImportStatus @default(PENDING)\n  totalRecords     Int          @default(0)\n  processedRecords Int          @default(0)\n  failedRecords    Int          @default(0)\n  errorMessage     String?\n  completedAt      DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  uploadedBy   User         @relation(fields: [uploadedById], references: [id])\n  prospects    Prospect[]\n\n  @@index([organizationId, status])\n}\n\n// --------------------------------------------------\n// 19. Email Template\n// Reusable templates for campaigns\n// --------------------------------------------------\n\nmodel EmailTemplate {\n  id             String @id @default(uuid()) @db.Uuid\n  organizationId String @db.Uuid\n  createdById    String @db.Uuid\n  name           String\n  subject        String\n  body           String @db.Text\n  variables      Json? // e.g. [\"firstName\", \"company\"]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization    @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  createdBy    User            @relation(\"TemplateCreatedBy\", fields: [createdById], references: [id])\n  campaigns    EmailCampaign[]\n\n  @@index([organizationId])\n}\n\n// --------------------------------------------------\n// 20. Email Campaign\n// --------------------------------------------------\n\nmodel EmailCampaign {\n  id             String         @id @default(uuid()) @db.Uuid\n  organizationId String         @db.Uuid\n  createdById    String         @db.Uuid\n  templateId     String?        @db.Uuid\n  name           String\n  subject        String\n  templateBody   String\n  status         CampaignStatus @default(DRAFT)\n  scheduledAt    DateTime?\n  startedAt      DateTime?\n  completedAt    DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization      Organization       @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  createdBy         User               @relation(fields: [createdById], references: [id])\n  template          EmailTemplate?     @relation(fields: [templateId], references: [id], onDelete: SetNull)\n  campaignProspects CampaignProspect[]\n  emailActivities   EmailActivity[]\n\n  @@index([organizationId, status])\n}\n\nmodel CampaignProspect {\n  campaignId String   @db.Uuid\n  prospectId String   @db.Uuid\n  addedAt    DateTime @default(now())\n\n  campaign EmailCampaign @relation(fields: [campaignId], references: [id], onDelete: Cascade)\n  prospect Prospect      @relation(fields: [prospectId], references: [id], onDelete: Cascade)\n\n  @@id([campaignId, prospectId])\n}\n\n// --------------------------------------------------\n// 20. Email Activity & Tracking\n// --------------------------------------------------\n\nmodel EmailActivity {\n  id             String         @id @default(uuid()) @db.Uuid\n  organizationId String         @db.Uuid\n  campaignId     String?        @db.Uuid\n  prospectId     String         @db.Uuid\n  type           EmailEventType\n  providerMsgId  String?\n  metadata       Json?\n\n  createdAt DateTime @default(now())\n\n  organization Organization   @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  campaign     EmailCampaign? @relation(fields: [campaignId], references: [id], onDelete: SetNull)\n  prospect     Prospect       @relation(fields: [prospectId], references: [id], onDelete: Cascade)\n  aiAnalyses   AiAnalysis[]\n\n  @@index([prospectId, type])\n  @@index([organizationId, campaignId])\n}\n\n// --------------------------------------------------\n// 21. AI Analysis\n// --------------------------------------------------\n\nmodel AiAnalysis {\n  id              String      @id @default(uuid()) @db.Uuid\n  organizationId  String      @db.Uuid\n  prospectId      String      @db.Uuid\n  emailActivityId String?     @db.Uuid // Optional link to a specific reply\n  sentiment       AiSentiment @default(NEUTRAL)\n  intent          AiIntent    @default(NONE)\n  confidenceScore Float       @default(0)\n  summary         String?\n  rawResponse     Json?\n\n  createdAt DateTime @default(now())\n\n  organization  Organization   @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  prospect      Prospect       @relation(fields: [prospectId], references: [id], onDelete: Cascade)\n  emailActivity EmailActivity? @relation(fields: [emailActivityId], references: [id], onDelete: SetNull)\n\n  @@index([prospectId])\n}\n\n// --------------------------------------------------\n// 22. AI Lead Engine Enums\n// --------------------------------------------------\n\nenum ProspectQualification {\n  UNQUALIFIED\n  COLD\n  WARM\n  HOT\n  SPAM\n  DISQUALIFIED\n}\n\nenum ImportStatus {\n  PENDING\n  PROCESSING\n  COMPLETED\n  FAILED\n}\n\nenum CampaignStatus {\n  DRAFT\n  SCHEDULED\n  RUNNING\n  COMPLETED\n  CANCELLED\n  FAILED\n}\n\nenum EmailEventType {\n  SENT\n  DELIVERED\n  OPENED\n  CLICKED\n  REPLIED\n  BOUNCED\n  FAILED\n  UNSUBSCRIBED\n}\n\nenum AiSentiment {\n  POSITIVE\n  NEUTRAL\n  NEGATIVE\n}\n\nenum AiIntent {\n  NONE\n  MEETING_REQUEST\n  CALL_REQUEST\n  PRICING_REQUEST\n  DEMO_REQUEST\n  MORE_INFO\n  NOT_INTERESTED\n  OUT_OF_OFFICE\n  WRONG_PERSON\n}\n\n// ==================================================\n// PHASE 6 — Field Force\n// ==================================================\n\nmodel Attendance {\n  id             String           @id @default(uuid()) @db.Uuid\n  organizationId String           @db.Uuid\n  userId         String           @db.Uuid\n  date           DateTime         @db.Date\n  checkInAt      DateTime?\n  checkOutAt     DateTime?\n  checkInLoc     Json?\n  checkOutLoc    Json?\n  status         AttendanceStatus @default(ABSENT)\n  durationMins   Int?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  user         User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, date])\n  @@index([organizationId, date])\n}\n\nmodel Visit {\n  id             String      @id @default(uuid()) @db.Uuid\n  organizationId String      @db.Uuid\n  userId         String      @db.Uuid\n  leadId         String?     @db.Uuid\n  title          String\n  type           VisitType   @default(MEETING)\n  status         VisitStatus @default(PLANNED)\n  scheduledAt    DateTime\n  completedAt    DateTime?\n  location       Json?\n  notes          String?\n  photoUrl       String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  user         User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n  lead         Lead?        @relation(fields: [leadId], references: [id], onDelete: SetNull)\n\n  @@index([organizationId, userId])\n  @@index([leadId])\n}\n\nmodel Expense {\n  id             String          @id @default(uuid()) @db.Uuid\n  organizationId String          @db.Uuid\n  userId         String          @db.Uuid\n  approvedById   String?         @db.Uuid\n  amount         Float\n  category       ExpenseCategory\n  date           DateTime        @db.Date\n  status         ExpenseStatus   @default(PENDING)\n  receiptUrl     String?\n  notes          String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  user         User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n  approvedBy   User?        @relation(\"ExpenseApprover\", fields: [approvedById], references: [id], onDelete: SetNull)\n\n  @@index([organizationId, userId])\n}\n\nmodel DailyActivityReport {\n  id             String    @id @default(uuid()) @db.Uuid\n  organizationId String    @db.Uuid\n  userId         String    @db.Uuid\n  date           DateTime  @db.Date\n  totalVisits    Int       @default(0)\n  totalOrders    Int       @default(0)\n  summary        String?\n  status         DarStatus @default(DRAFT)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  user         User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, date])\n}\n\nenum AttendanceStatus {\n  PRESENT\n  ABSENT\n  LEAVE\n  HALFDAY\n}\n\nenum VisitType {\n  COLD_CALL\n  FOLLOW_UP\n  MEETING\n  DEMO\n}\n\nenum VisitStatus {\n  PLANNED\n  IN_PROGRESS\n  COMPLETED\n  CANCELLED\n}\n\nenum ExpenseCategory {\n  TRAVEL\n  MEALS\n  ACCOMMODATION\n  OTHER\n}\n\nenum ExpenseStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nenum DarStatus {\n  DRAFT\n  SUBMITTED\n  APPROVED\n}\n\n// ==================================================\n// PHASE 7 — Target & Performance\n// ==================================================\n\nmodel Target {\n  id             String       @id @default(uuid()) @db.Uuid\n  organizationId String       @db.Uuid\n  userId         String?      @db.Uuid\n  teamId         String?      @db.Uuid\n  metric         TargetMetric\n  period         TargetPeriod\n  startDate      DateTime     @db.Date\n  endDate        DateTime     @db.Date\n  targetValue    Float\n  achievedValue  Float        @default(0)\n  status         TargetStatus @default(ACTIVE)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  user         User?        @relation(fields: [userId], references: [id], onDelete: Cascade)\n  team         Team?        @relation(fields: [teamId], references: [id], onDelete: Cascade)\n\n  @@index([organizationId, metric, period])\n}\n\nenum TargetMetric {\n  REVENUE\n  VISITS\n  NEW_LEADS\n  CONVERSIONS\n  ATTENDANCE\n  DAR\n  ACTIVITIES\n}\n\nenum TargetPeriod {\n  MONTHLY\n  QUARTERLY\n  YEARLY\n}\n\nenum TargetStatus {\n  ACTIVE\n  CLOSED\n}\n\n// ==================================================\n// PHASE 8 — Notifications\n// ==================================================\n\nmodel Notification {\n  id             String             @id @default(uuid()) @db.Uuid\n  organizationId String             @db.Uuid\n  userId         String             @db.Uuid\n  title          String\n  message        String\n  type           NotificationType\n  status         NotificationStatus @default(UNREAD)\n  referenceType  String?\n  referenceId    String?            @db.Uuid\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  user         User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([organizationId, userId])\n}\n\nmodel NotificationTemplate {\n  id             String           @id @default(uuid()) @db.Uuid\n  organizationId String           @db.Uuid\n  name           String           @unique\n  subject        String?\n  body           String\n  type           NotificationType\n  variables      Json?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n}\n\nenum NotificationType {\n  EMAIL\n  SMS\n  IN_APP\n}\n\nenum NotificationStatus {\n  UNREAD\n  READ\n}\n\n// ==================================================\n// PHASE 9 — Tasks, Beat Plans, Calendar\n// ==================================================\n\nmodel Task {\n  id             String    @id @default(uuid()) @db.Uuid\n  organizationId String    @db.Uuid\n  userId         String    @db.Uuid\n  title          String\n  description    String?\n  status         String    @default(\"PENDING\")\n  dueDate        DateTime?\n  referenceType  String?\n  referenceId    String?   @db.Uuid\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  user         User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([organizationId, userId])\n}\n\nmodel BeatPlan {\n  id             String   @id @default(uuid()) @db.Uuid\n  organizationId String   @db.Uuid\n  userId         String   @db.Uuid\n  title          String\n  startDate      DateTime\n  endDate        DateTime\n  status         String   @default(\"DRAFT\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  user         User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([organizationId, userId])\n}\n\nmodel CalendarEvent {\n  id             String   @id @default(uuid()) @db.Uuid\n  organizationId String   @db.Uuid\n  userId         String   @db.Uuid\n  title          String\n  description    String?\n  startTime      DateTime\n  endTime        DateTime\n  type           String\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  user         User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([organizationId, userId])\n}\n\n// ==================================================\n// PHASE 10 — Settings\n// ==================================================\n\nmodel WorkflowSettings {\n  id                String  @id @default(uuid()) @db.Uuid\n  organizationId    String  @db.Uuid\n  autoAssign        Boolean @default(true)\n  requireApproval   Boolean @default(true)\n  approvalHierarchy Json? // Configuration of who approves what\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n\n  @@index([organizationId])\n}\n\nmodel NotificationPreference {\n  id             String  @id @default(uuid()) @db.Uuid\n  organizationId String  @db.Uuid\n  userId         String  @db.Uuid\n  emailEnabled   Boolean @default(true)\n  smsEnabled     Boolean @default(false)\n  inAppEnabled   Boolean @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  user         User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([organizationId, userId])\n}\n\nmodel BusinessRuleConfig {\n  id             String  @id @default(uuid()) @db.Uuid\n  organizationId String  @db.Uuid\n  ruleKey        String // e.g. \"MAX_LEADS_PER_DAY\"\n  ruleValue      String // e.g. \"50\"\n  description    String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n\n  @@unique([organizationId, ruleKey])\n}\n\n// ==================================================\n// PHASE 6 — Campaign Management\n// ==================================================\n\nmodel Campaign {\n  id              String            @id @default(uuid()) @db.Uuid\n  organizationId  String            @db.Uuid\n  name            String\n  description     String?\n  status          CampaignRunStatus @default(Draft)\n  campaignChannel CampaignChannel?\n  category        String?\n  serviceType     String?\n  templateId      String?           @db.Uuid\n  emailProvider   EmailProvider?\n  scheduledAt     DateTime?\n  startedAt       DateTime?\n  completedAt     DateTime?\n  createdById     String            @db.Uuid\n  updatedById     String            @db.Uuid\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organization  Organization   @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  createdBy     User           @relation(\"CampaignCreatedBy\", fields: [createdById], references: [id])\n  updatedBy     User           @relation(\"CampaignUpdatedBy\", fields: [updatedById], references: [id])\n  campaignLeads CampaignLead[]\n  campaignLogs  CampaignLog[]\n\n  @@index([organizationId, status])\n}\n\nmodel CampaignLead {\n  id          String             @id @default(uuid()) @db.Uuid\n  campaignId  String             @db.Uuid\n  leadId      String             @db.Uuid\n  email       String\n  contactName String?\n  company     String?\n  status      CampaignLeadStatus @default(Pending)\n  replyType   ReplyType          @default(None)\n\n  sentAt       DateTime?\n  openedAt     DateTime?\n  clickedAt    DateTime?\n  repliedAt    DateTime?\n  errorMessage String?\n\n  campaign     Campaign      @relation(fields: [campaignId], references: [id], onDelete: Cascade)\n  lead         Lead          @relation(fields: [leadId], references: [id], onDelete: Cascade)\n  campaignLogs CampaignLog[]\n\n  @@index([campaignId, status])\n  @@index([leadId])\n}\n\nmodel CampaignLog {\n  id               String  @id @default(uuid()) @db.Uuid\n  campaignId       String  @db.Uuid\n  leadId           String? @db.Uuid\n  event            String\n  status           String\n  message          String?\n  providerResponse Json?\n\n  createdAt DateTime @default(now())\n\n  campaign Campaign      @relation(fields: [campaignId], references: [id], onDelete: Cascade)\n  lead     CampaignLead? @relation(fields: [leadId], references: [id], onDelete: SetNull)\n\n  @@index([campaignId])\n  @@index([leadId])\n}\n\nenum CampaignRunStatus {\n  Draft\n  Scheduled\n  Running\n  Paused\n  Completed\n  Cancelled\n}\n\nenum CampaignChannel {\n  Email\n  SMS\n  WhatsApp\n}\n\nenum EmailProvider {\n  SMTP\n  Gmail\n}\n\nenum CampaignLeadStatus {\n  Pending\n  Queued\n  Sent\n  Delivered\n  Opened\n  Clicked\n  Replied\n  Interested\n  DemoScheduled\n  Qualified\n  Lost\n  Failed\n}\n\nenum ReplyType {\n  None\n  Interested\n  Demo\n  Pricing\n  NotInterested\n  Other\n}\n"
}

